Hi Wenzel, I noticed that if i try to overload virtual functions that take parameter by-reference it does not work as expected: instead of receiving original parameters (the one that C++ function was called with) the Python version will receive copy of parameter instead. Curiously this does not happened when overloading function accepting parameter by-pointer. Such copy behavior is problematic in two ways: 

1. Copy operation could be expensive and 
2. It makes impossible for overloading function to modify supplied value (because it only can modify copy of it)

Is this something that could be fixed or current design does not permit it? If later: i found a workaround for this issue: during the Py-call-back definition we can just call macro and supply referenced parameter converted to pointer with `&` (see implementation of `test_ref_workaround` below). So perhaps it will be a good idea to mention this in the docs if there is no way to fix this?

Thank you,

Sergey.

```C++
#include <pybind11/pybind11.h>
#include <iostream>
#include <vector>

PYBIND11_DECLARE_HOLDER_TYPE(T, std::shared_ptr<T>);

class Value
{
public:
	Value(std::string s="unknown") { s_=s; }
	Value( Value const & src ) { std::cout << "Value Copy constructor! ["<< src.s_ << "]" << std::endl; }

	~Value() { std::cout << "Value destructor!  ["<< s_ << "]" << std::endl; }

	std::string s_;

	Value &operator=(const Value &v) {
		std::cout << "Value operator assign! ["<< v.s_ << "]" << std::endl;
		s_ = v.s_;
		return *this;
	}
};


class OverloadTest
{
public:
	Value value_;

	void self_test_ref() {
		std::cout << "Calling test_ref(Value &v)..." << std::endl;
		test_ref(value_);
		std::cout << "Calling test_ref(Value &v)... Done!" << std::endl;
	}

	void self_test_p() {
		std::cout << "Calling test_p(Value *v)..." << std::endl;
		test_p(&value_);
		std::cout << "Calling test_p(Value *v)... Done!" << std::endl;
	}

	void self_test_ref_workaround() {
		std::cout << "Calling test_ref_workaround(Value &v)..." << std::endl;
		test_ref_workaround(value_);
		std::cout << "Calling test_ref_workaround(Value &v)... Done!" << std::endl;
	}

	virtual void test_p(Value *v) {}
	virtual void test_ref(Value &v) {}
	virtual void test_ref_workaround(Value &v) {}
};


struct PyCallBack_OverloadTest : public OverloadTest {
	using OverloadTest::OverloadTest;

	using _binder_base_ = OverloadTest;

	void test_ref(class Value & a0) override { PYBIND11_OVERLOAD_NAME(void, _binder_base_, "test_ref", OverloadTest::test_ref, a0 ); }

	// Workaround: pretend that we getting pointer instead of reference, note that we pass '&a0' to macro...
	void test_ref_workaround(class Value & a0) override {
		PYBIND11_OVERLOAD_INT(void, "test_ref_workaround", &a0)
		return _binder_base_::OverloadTest::test_ref_workaround(a0);
	}

	void test_p(class Value * a0) override { PYBIND11_OVERLOAD_NAME(void, _binder_base_, "test_p", OverloadTest::test_p, a0); }
};


namespace py = pybind11;

PYBIND11_PLUGIN(example) {
    py::module m("example", "pybind11 example plugin");

	{
		pybind11::class_<Value> cl(m, "Value");
		pybind11::handle cl_type = cl;

		cl.def("__init__", [](Value *self_) { new (self_) Value(); });
		cl.def(pybind11::init<class std::basic_string<char>>(), pybind11::arg("s"));

		cl.def(pybind11::init<const class Value &>(), pybind11::arg("src"));

		cl.def_readwrite("s_", &Value::s_);
		cl.def("assign", &Value::operator=);
	}

	{
		pybind11::class_<OverloadTest, std::shared_ptr<OverloadTest>, PyCallBack_OverloadTest> cl(m, "OverloadTest");
		pybind11::handle cl_type = cl;

		cl.def(pybind11::init<>());
		cl.def(pybind11::init<PyCallBack_OverloadTest const &>());

		cl.def_readwrite("value_", &OverloadTest::value_);

		cl.def("self_test_p",              &OverloadTest::self_test_p);
		cl.def("self_test_ref",            &OverloadTest::self_test_ref);
		cl.def("self_test_ref_workaround", &OverloadTest::self_test_ref_workaround);

		cl.def("test_ref", &OverloadTest::test_ref);
		cl.def("test_p",   &OverloadTest::test_p);
	}

    return m.ptr();
}
```

```python
from __future__ import print_function

from example import *

class PyOverloadTest(OverloadTest):
    def __init__(self):
        OverloadTest.__init__(self)
        self.value_.s_ = '_py_'

    def test_p(self, v): print('PyOverloadTest.test_p({})'.format(v.s_))
    def test_ref(self, v): print('PyOverloadTest.test_ref({})'.format(v.s_))
    def test_ref_workaround(self, v): print('PyOverloadTest.test_ref_workaround({})'.format(v.s_))


print('OverloadTest Test -----------------------')
ot = OverloadTest()
ot.self_test_p()
ot.self_test_ref()

print('PyOverloadTest Test -----------------------------------------')
pot = PyOverloadTest()
print()
pot.self_test_p()
print()
pot.self_test_ref()
print()
pot.self_test_ref_workaround()
print()
```

